import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface WaveHeight {
  time: string;
  height: number;
}

interface TideData {
  location: string;
  current: {
    tideLevel: number;
    condition: string;
    nextHigh: string;
    nextLow: string;
  };
  waveHeightChart: WaveHeight[];
}

export default function Widget() {
  const tideData = response.data as TideData;
  const { location, current, waveHeightChart } = tideData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#E3F2FD' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" color="primary">
              Tide Tracker
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {location}
            </Typography>
            <Typography variant="h4" fontWeight={300} sx={{ my: 0.5 }} color="primary">
              {current.tideLevel} ft
            </Typography>
            <Typography variant="body1" color="text.secondary">
              Current Condition: {current.condition}
            </Typography>
            <Typography variant="caption" color="text.secondary">
              Next High Tide: {current.nextHigh} | Next Low Tide: {current.nextLow}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: waveHeightChart.map(point => point.height),
                  color: '#00796B',
                  label: 'Wave Height',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: waveHeightChart.map(point => point.time),
                  id: 'time',
                },
              ]}
              yAxis={[{ id: 'height' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsYAxis
                axisId="height"
                tickLabelStyle={{ fontSize: 10, fill: '#6B7280' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
